import React, {useState} from 'react';
import hobbiesConfig from './config/hobbiesConfig.json'
const Hobbies = () => {
    const [isConfig, SetConfig] = useState(hobbiesConfig);
    const [isShown, SetShown] = useState(false);
    const [isToggled, SetToggle] = useState('down');
    const handleClick = (bool) => {
        SetShown(bool);
        if (bool)
            SetToggle('up');
        else
            SetToggle("down");

    };
    return (
        <>
            {isConfig.map((config) => {
                return (
                    <div onClick={() => handleClick(!isShown)}>
                        <div className={`ui center ${config.segmentColor} segment`}

                        >
                            <h3>
                                <>
                                {config.image ? (
                                    ImageICON
                                ) :(
                                    <i className={`${config.icon} icon`}></i>
                                )
                                }
                                </>
                                <>
                                {config.hobby}
                                </>
                                {isShown ? (
                                    <i className={`angle ${isToggled} icon`}></i>
                                ): (
                                    <i className={`angle ${isToggled} icon`}></i>
                                )
                                }
                            </h3>
                            {isShown && (
                                <div className="ui center"><p>{config.content}</p></div>
                            )}
                        </div>

                    </div>
                )
            })

            }

            )
        </>
    )
}

export default Hobbies;
